\subsection*{Esercizio 1: Nomenclatura e Strutture di Composti Organici}
\begin{enumerate}[a)]
\item Assegna il nome IUPAC corretto ai seguenti composti organici: (7 pt)
\begin{enumerate}[i)]
\item CH$_3$CH$_2$CH$_2$CH$_2$OH (1 pt)
\item (CH$_3$)$_2$CHCOCH$_3$ (2 pt)
\item CH$_2$=CH-CH=CH$_2$ (1 pt)
\item C$_6$H$_5$NO$_2$ (2 pt)
\end{enumerate}
\item Disegna la struttura di Lewis per il metanolo (CH$_3$OH) e per l'anidride carbonica (CO$_2$). Evidenzia gli elettroni di valenza. (7 pt)
\item Classifica i seguenti composti come alcani, alcheni, alchini, alcoli o aldeidi: (7 pt)
\begin{enumerate}[i)]
\item Etano (1 pt)
\item Protene (2 pt)
\item Acetilene (2 pt)
\item Metanale (2 pt)
\item 2-Butanolo (2 pt)
\end{enumerate}
\item Indica il tipo di ibridazione degli atomi di carbonio nelle seguenti molecole: (8 pt)
\begin{enumerate}[i)]
\item Etano (CH$_3$CH$_3$) (2 pt)
\item Etene (CH$_2$=CH$_2$) (2 pt)
\item Etino (CH$\equiv$CH) (3 pt)
\end{enumerate}
\end{enumerate}

\subsection*{Esercizio 2: Reazioni di Composti Organici}
\begin{enumerate}[a)]
\item Scrivi le reazioni di ossidazione del propan-1-olo e del propan-2-olo con un ossidante blando (es. PCC). Indica i prodotti formati. (11 pt)
\item Bilancia la seguente reazione di combustione completa dell'etano (C$_2$H$_6$): (8 pt)
C$_2$H$_6$ + O$_2$ $\rightarrow$ CO$_2$ + H$_2$O
\item Descrivi brevemente il meccanismo di addizione elettrofila dell'idrogeno bromuro (HBr) all'etilene (CH$_2$=CH$_2$). Indica il prodotto principale formato, giustificando la regioselettività secondo la regola di Markovnikov. (11 pt)
\end{enumerate}

\subsection*{Esercizio 3: Isomeria e Proprietà Fisiche}
\begin{enumerate}[a)]
\item Identifica tutti gli isomeri strutturali (scheletrici e di posizione) dell'esano (C$_6$H$_{14}$). Assegna il nome IUPAC a ciascun isomero. (15 pt)
\item Confronta i punti di ebollizione dei seguenti composti e giustifica la differenza: (8 pt)
\begin{itemize}
    \item n-pentano (4 pt)
    \item isopentano (2-metilbutano) (4 pt)
\end{itemize}
\item Spiega la differenza tra isomeri cis e trans nel contesto degli alcheni, fornendo un esempio specifico (es. 2-butene). (8 pt)
\end{enumerate}
